        min_node = start
        while queue:
            node = queue.popleft()
            if online[node]:
                min_node = min(min_node, node)
            for neighbor in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return min_node

